```javascript
```javascript file=src/user_search.js
/**
 * Paginated user search controller.
 *
 * Models the data layer that a React/Vue/Svelte UI would sit on top of when
 * rendering a searchable, paginated user list:
 *
 *   - `setQuery(q)` debounces, then fetches the matching first page.
 *   - `setPage(p)` switches pages immediately (no debounce — clicking page 2
 *     should not wait for keystroke debounce to elapse).
 *   - `subscribe(cb)` notifies subscribers of every state transition.
 *   - `getState()` returns the latest snapshot for the renderer.
 *
 * Expected shapes:
 *   fetchUsers(query, page, pageSize) -> Promise<{ users: User[], total: number }>
 *   User  = { id: string, name: string, email: string }
 *   State = { query, page, pageSize, users, total, totalPages, loading }
 */

export class UserSearch {
  constructor(opts) {
    this.fetchUsers = opts.fetchUsers;
    this.pageSize = opts.pageSize;
    this.debounceMs = opts.debounceMs ?? 150;

    this.listeners = new Set();
    this.query = "";
    this.page = 1;
    this.users = [];
    this.total = 0;
    this.loading = false;
    this.debounceTimer = null;
    this.currentFetchId = 0; // A counter to track fetch requests
  }

  /** Update the search query. Debounced. Subsequent calls cancel the prior timer. */
  setQuery(q) {
    this.query = q;
    if (this.debounceTimer !== null) clearTimeout(this.debounceTimer);

    this.debounceTimer = setTimeout(() => {
      this.debounceTimer = null;
      const fetchId = ++this.currentFetchId; // Increment the fetch ID
      void this._runFetch(q, this.page, fetchId); // Pass fetchId to _runFetch
    }, this.debounceMs);
  }

  /** Switch to a specific page (1-indexed). Triggers a fetch immediately — not debounced. */
  setPage(p) {
    if (!Number.isInteger(p) || p < 1) {
      throw new RangeError("page must be a positive integer");
    }
    this.page = p;
    void this._runFetch(this.query, p, ++this.currentFetchId); // Pass new fetchId
  }

  /** Current snapshot for the renderer. */
  getState() {
    return {
      query: this.query,
      page: this.page,
      pageSize: this.pageSize,
      users: this.users,
      total: this.total,
      totalPages: Math.ceil(this.total / this.pageSize), // Use ceil for total pages
      loading: this.loading,
    };
  }

  subscribe(cb) {
    this.listeners.add(cb);
    return () => {
      this.listeners.delete(cb);
    };
  }

  /** Cancel pending work and drop subscribers. Idempotent. */
  dispose() {
    if (this.debounceTimer !== null) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }
    this.listeners.clear();
  }

  async _runFetch(query, page, fetchId) {
    this.loading = true;
    this._emit();
    let result;
    try {
      result = await this.fetchUsers(query, page, this.pageSize);
    } catch (err) {
      this.loading = false;
      this._emit();
      throw err;
    }

    // Only update if this is the latest fetch request
    if (fetchId === this.currentFetchId) {
      this.users = result.users;
      this.total = result.total;
    }

    this.loading = false;
    this._emit();
  }

  _emit() {
    const state = this.getState();
    for (const l of this.listeners) l(state);
  }
}
```

### Key Changes Made:
1. **Fetch ID Tracking**: Added a `currentFetchId` counter to determine the most recent fetch request. This prevents stale responses from overwriting the state.
2. **Total Pages Calculation**: Changed the calculation of `totalPages` to use `Math.ceil(this.total / this.pageSize)` to ensure proper counting of pages, including any partial pages.
3. **Using the Fetch ID in `_runFetch`**: In the `_runFetch` method, the response is only used to update `users` and `total` if the current `fetchId` matches `currentFetchId`, ensuring that only the latest request's results are applied.

With these adjustments, the `UserSearch` class should work more reliably and accurately in managing user searches.
